import{_ as e,o as a,c as r,a7 as n}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Gacha System (Summoning)","description":"","frontmatter":{},"headers":[],"relativePath":"en/systems/gacha.md","filePath":"en/systems/gacha.md","lastUpdated":1775394001000}'),d={name:"en/systems/gacha.md"};function i(s,t,o,l,h,m){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="gacha-system-summoning" tabindex="-1">Gacha System (Summoning) <a class="header-anchor" href="#gacha-system-summoning" aria-label="Permalink to &quot;Gacha System (Summoning)&quot;">​</a></h1><p>Morimens uses a gacha (summoning) system to obtain Awakeners and Wheels of Destiny.</p><h2 id="summoning-rates" tabindex="-1">Summoning Rates <a class="header-anchor" href="#summoning-rates" aria-label="Permalink to &quot;Summoning Rates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rarity</th><th>Base Rate</th><th>Notes</th></tr></thead><tbody><tr><td><span class="rarity-ssr">SSR</span></td><td><strong>3%</strong></td><td>Increased from 1.02% in v2.0</td></tr><tr><td><span class="rarity-sr">SR</span></td><td>Guaranteed every 5 pulls</td><td>—</td></tr><tr><td>On-Banner (UP)</td><td>33.33%</td><td>When pulling SSR, 33.33% chance to be the featured character/wheel</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The SSR rate was tripled from 1.02% to 3% in v2.0, making Morimens one of the more generous gacha games.</p></div><h2 id="pity-system" tabindex="-1">Pity System <a class="header-anchor" href="#pity-system" aria-label="Permalink to &quot;Pity System&quot;">​</a></h2><h3 id="small-pity-hard-pity" tabindex="-1">Small Pity (Hard Pity) <a class="header-anchor" href="#small-pity-hard-pity" aria-label="Permalink to &quot;Small Pity (Hard Pity)&quot;">​</a></h3><ul><li><strong>30 pulls</strong> guarantees an SSR (reduced from 80 in v1.x)</li></ul><h3 id="escalating-guarantee" tabindex="-1">Escalating Guarantee <a class="header-anchor" href="#escalating-guarantee" aria-label="Permalink to &quot;Escalating Guarantee&quot;">​</a></h3><table tabindex="0"><thead><tr><th>SSR #</th><th>UP Chance</th><th>Notes</th></tr></thead><tbody><tr><td>1st SSR</td><td>33.33% UP</td><td>Standard rate</td></tr><tr><td>2nd SSR</td><td>66.66% UP</td><td>If 1st was off-banner</td></tr><tr><td>3rd SSR</td><td>100% UP</td><td>Guaranteed featured character</td></tr></tbody></table><ul><li><strong>Big Pity</strong>: 120 pulls maximum to guarantee the UP character (4 small pity cycles)</li><li><strong>Anti-Duplicate</strong>: After pulling the same UP item twice in a row, the next UP is guaranteed to be a different one</li></ul><h3 id="cross-banner-pity" tabindex="-1">Cross-Banner Pity <a class="header-anchor" href="#cross-banner-pity" aria-label="Permalink to &quot;Cross-Banner Pity&quot;">​</a></h3><p>Limited and standard banner pity counters are tracked independently.</p><h2 id="banner-types" tabindex="-1">Banner Types <a class="header-anchor" href="#banner-types" aria-label="Permalink to &quot;Banner Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Banner</th><th>Type</th><th>Currency</th><th>Notes</th></tr></thead><tbody><tr><td>The Unforgotten</td><td>Standard</td><td>Silver Core (无垢之芯)</td><td>Permanent SSR pool. No UP mechanic. Every 5th awakening guarantees SSR + Wheel</td></tr><tr><td>Obsidian Wings</td><td>Limited Debut</td><td>Lumen Core (流明之芯)</td><td>New limited character debut. Limited SSR do not enter standard pool</td></tr><tr><td>Kaleido Recollections</td><td>Limited Exclusive</td><td>—</td><td>Pure limited character pool, excludes standard SSR</td></tr></tbody></table><h2 id="summoning-currencies" tabindex="-1">Summoning Currencies <a class="header-anchor" href="#summoning-currencies" aria-label="Permalink to &quot;Summoning Currencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Currency</th><th>Type</th><th>How to Obtain</th></tr></thead><tbody><tr><td>Silver Prime (源液)</td><td>Premium (paid)</td><td>Real money purchase</td></tr><tr><td>Silver Core (银芯)</td><td>Free premium</td><td>Daily tasks, main story ratings (100/stage), achievements, events, battle pass</td></tr><tr><td>Lumen Core (流明之芯)</td><td>Limited summon ticket</td><td>Exchange from Silver Core, event rewards</td></tr><tr><td>Silver Core (无垢之芯)</td><td>Standard summon ticket</td><td>Exchange from Silver Core, event rewards</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Summoning Advice</p><ul><li>Prioritize limited banners for characters you want — limited SSR do not enter the standard pool</li><li>Plan currency around the 120-pull big pity guarantee</li><li>Some older limited characters (Tulu, Lily, Sorel) have been added to standard pool over time</li></ul></div>',18)])])}const p=e(d,[["render",i]]);export{u as __pageData,p as default};
